import { useEffect, useState } from "react"
import { io } from "socket.io-client"
import axios from "axios"

const socket = io("http://localhost:5001")

export default function ChatPage({user}){
  const [other,setOther]=useState("")
  const [room,setRoom]=useState("")
  const [msg,setMsg]=useState("")
  const [list,setList]=useState([])      // initialize as empty array
  const [online,setOnline]=useState([])
  const [typingUser,setTypingUser]=useState("")

  useEffect(()=>{
    socket.emit('user_online',user.name)
    socket.on('online_users', setOnline)
    socket.on('receive_message', m=>setList(prev=>[...prev,m]))
    socket.on('typing', u=>setTypingUser(u))
    socket.on('message_read', id=>setList(prev=>prev.map(m=>m._id===id?{...m,read:true}:m)))
    return ()=>socket.off()
  },[])

      setList(res.data.messages || [])        // guard: default to empty array

  const handleTyping=()=>{ if(room) socket.emit('typing',room) }
  const handleRead=id=>{ if(room) socket.emit('message_read',{room,messageId:id}) }

  return <div style={{padding:20,background:"#e0f7ff",height:"100vh"}}>
    {!room ? <>
      <input placeholder="chat with" onChange={e=>setOther(e.target.value)} />
      <button onClick={joinRoom}>Start Chat</button>
    </> : <>
      <h2>Chat with {other}</h2>
      <div>Online: {online.join(", ")}</div>
      <div style={{margin:"10px 0", maxHeight:"60vh", overflowY:"auto"}}>
        {list && list.map(m=>
          <p key={m._id} onMouseEnter={()=>handleRead(m._id)}
             style={{
               background:m.sender===user.name?"#cceeff":"#ffffff",
               padding:5,
               borderRadius:5,
               marginBottom:5
             }}>
            <b>{m.sender}</b>: {m.text} 
            {m.sender===user.name && (m.read ? <span style={{color:"blue"}}> ✓✓</span> : <span> ✓✓</span>)}
          </p>
        )}
      </div>
      {typingUser && <div>{typingUser} is typing...</div>}
      <input placeholder="message" value={msg} onChange={e=>{setMsg(e.target.value);handleTyping()}} />
      <button onClick={send}>Send</button>
    </>}
  </div>
}
